// var vs let vs const
var x = 10;
if (true) {
  var x = 20;    // overwrites outer x — var ignores block scope
  let y = 30;    // only exists inside this block
  const z = 40;  // only exists inside this block
}
console.log(x); // 20 — var leaked out!
// console.log(y); // ReferenceError — let is block-scoped

// Type coercion traps
console.log('5' + 3);   // '53' — string concat
console.log('5' - 3);   // 2    — numeric subtraction
console.log(5 == '5');  // true — loose equality (avoid!)
console.log(5 === '5'); // false — strict equality (use this)

// Truthy/Falsy in React conditional rendering
const count = 0;
// BAD: renders '0' on screen because 0 is falsy but React still renders the number
const bad = count && <Badge />;  // renders '0' — bug!
// GOOD:
const good = count > 0 && <Badge />;  // renders nothing cleanly

// Optional chaining and nullish coalescing
const user = { profile: { name: 'Alice' } };
console.log(user?.profile?.name);   // 'Alice'
console.log(user?.address?.city);   // undefined (no crash)
console.log(user?.address?.city ?? 'Unknown'); // 'Unknown'

// Function declaration vs expression vs arrow
function declaredFn() { return 'hoisted'; }      // declaration
const expressionFn = function() { return 'not hoisted'; };  // expression
const arrowFn = () => 'concise';                 // arrow (implicit return)

// Arrow function — implicit return (no braces needed for single expression)
const double = x => x * 2;
const add = (a, b) => a + b;
const getUser = id => ({ id, name: 'Alice' });   // wrap object in ()

// 'this' context difference
class Timer {
  constructor() {
    this.count = 0;
  }

  // Regular function — loses 'this' when used as callback
  startBad() {
    setInterval(function() {
      this.count++; // 'this' is undefined here in strict mode!
    }, 1000);
  }

  // Arrow function — inherits 'this' from Timer instance
  startGood() {
    setInterval(() => {
      this.count++; // 'this' correctly refers to Timer instance
    }, 1000);
  }
}

