// ===== Class Component =====
import React, { Component } from 'react';

class Counter extends Component {
  constructor(props) {
    super(props);           // MUST call super(props)
    this.state = { count: 0 };
    // Bind needed for regular methods to access 'this'
    this.handleClick = this.handleClick.bind(this);
  }

  handleClick() {
    this.setState({ count: this.state.count + 1 });
  }

  render() {
    return (
      <div>
        <p>Count: {this.state.count}</p>
        <button onClick={this.handleClick}>Increment</button>
      </div>
    );
  }
}

// ===== Equivalent Functional Component (modern) =====
import React, { useState } from 'react';

function Counter() {
  const [count, setCount] = useState(0);

  return (
    <div>
      <p>Count: {count}</p>
      <button onClick={() => setCount(count + 1)}>Increment</button>
    </div>
  );
}

export default Counter;

import React, { Component } from 'react';

class UserProfile extends Component {
  constructor(props) {
    super(props);  // REQUIRED: initializes this.props
    // Initialize state
    this.state = {
      isExpanded: false,
      likesCount: 0,
    };
    // Bind regular methods (arrow class properties avoid this)
    this.handleToggle = this.handleToggle.bind(this);
  }

  handleToggle() {
    // setState merges — only isExpanded changes, likesCount stays
    this.setState({ isExpanded: !this.state.isExpanded });
  }

  // Arrow function as class property — auto-bound, no binding needed
  handleLike = () => {
    // Functional setState for state depending on previous value
    this.setState(prevState => ({ likesCount: prevState.likesCount + 1 }));
  }

  render() {
    const { name, bio, avatar } = this.props;  // destructure props
    const { isExpanded, likesCount } = this.state;

    return (
      <div className="user-profile">
        <img src={avatar} alt={name} />
        <h2>{name}</h2>
        {isExpanded && <p>{bio}</p>}
        <button onClick={this.handleToggle}>
          {isExpanded ? 'Show Less' : 'Show More'}
        </button>
        <button onClick={this.handleLike}>❤️ {likesCount}</button>
      </div>
    );
  }
}

// Usage:
// <UserProfile name="Alice" bio="React Developer" avatar="pic.jpg" />

export default UserProfile;

