import React, { Component } from 'react';

class DataFetcher extends Component {
  constructor(props) {
    super(props);
    this.state = { data: null, loading: true, error: null };
    this.intervalId = null;
  }

  // MOUNTING: runs once after first render — ideal for API calls
  async componentDidMount() {
    try {
      const res = await fetch(`https://api.example.com/data/${this.props.id}`);
      const data = await res.json();
      this.setState({ data, loading: false });
    } catch (error) {
      this.setState({ error: error.message, loading: false });
    }

    // Set up a timer
    this.intervalId = setInterval(() => {
      console.log('Polling for updates...');
    }, 5000);
  }

  // UPDATING: runs after every re-render (compare prevProps to avoid loops)
  componentDidUpdate(prevProps, prevState) {
    if (prevProps.id !== this.props.id) {
      // id prop changed — fetch new data
      this.setState({ loading: true });
      this.fetchData(this.props.id);
    }
  }

  // UNMOUNTING: cleanup before removal — prevents memory leaks!
  componentWillUnmount() {
    clearInterval(this.intervalId);  // clear timer
    // cancel any pending API requests here
    console.log('Component cleaned up');
  }

  fetchData = async (id) => {
    const res = await fetch(`https://api.example.com/data/${id}`);
    const data = await res.json();
    this.setState({ data, loading: false });
  }

  render() {
    const { data, loading, error } = this.state;
    if (loading) return <div>Loading...</div>;
    if (error) return <div>Error: {error}</div>;
    return <div>{JSON.stringify(data)}</div>;
  }
}

export default DataFetcher;

import React, { useState } from 'react';

// ===== Functional Component Event Handling (Modern) =====
function EventDemo() {
  const [inputValue, setInputValue] = useState('');
  const [clicked, setClicked] = useState(0);
  const [selected, setSelected] = useState('none');

  // Handler defined in component body — no binding needed
  const handleButtonClick = (event) => {
    console.log('Event type:', event.type);   // 'click'
    console.log('Target:', event.target);     // the button element
    setClicked(prev => prev + 1);
  };

  const handleInputChange = (event) => {
    setInputValue(event.target.value);  // event.target.value gets input text
  };

  const handleFormSubmit = (event) => {
    event.preventDefault();  // CRITICAL: prevents page reload
    alert(`Submitted: ${inputValue}`);
  };

  // Passing extra data to handler via arrow function wrapper
  const handleItemClick = (itemId, itemName) => {
    console.log(`Clicked item ${itemId}: ${itemName}`);
  };

  // Stopping propagation
  const handleCardClick = () => console.log('Card clicked');
  const handleButtonInsideCard = (e) => {
    e.stopPropagation();  // prevents handleCardClick from also firing
    console.log('Button inside card clicked');
  };

  return (
    <div>
      {/* Basic click */}
      <button onClick={handleButtonClick}>Clicked {clicked} times</button>

      {/* Inline arrow function — OK for simple cases */}
      <button onClick={() => setClicked(0)}>Reset</button>

      {/* Input change */}
      <input
        type="text"
        value={inputValue}       // controlled input
        onChange={handleInputChange}
        placeholder="Type here"
      />
      <p>You typed: {inputValue}</p>

      {/* Form submit */}
      <form onSubmit={handleFormSubmit}>
        <input type="text" value={inputValue} onChange={handleInputChange} />
        <button type="submit">Submit</button>
      </form>

      {/* Passing arguments via arrow function wrapper */}
      {['Laptop', 'Phone', 'Tablet'].map((item, idx) => (
        <div key={idx} onClick={() => handleItemClick(idx, item)}>
          {item}
        </div>
      ))}

      {/* Select / dropdown */}
      <select value={selected} onChange={e => setSelected(e.target.value)}>
        <option value="none">Select...</option>
        <option value="react">React</option>
        <option value="vue">Vue</option>
      </select>
      <p>Selected: {selected}</p>

      {/* Stoppage propagation */}
      <div onClick={handleCardClick} style={{ border: '1px solid', padding: 20 }}>
        Card (click anywhere)
        <button onClick={handleButtonInsideCard}>Button (no card click)</button>
      </div>
    </div>
  );
}

export default EventDemo;

import React, { useState, useEffect } from 'react';

// ===== HOC 1: withAuth — redirect if not authenticated =====
function withAuth(WrappedComponent) {
  return function AuthenticatedComponent(props) {
    const isAuthenticated = localStorage.getItem('token');

    if (!isAuthenticated) {
      return (
        <div>
          <p>Please log in to view this page.</p>
          <a href="/login">Login</a>
        </div>
      );
    }

    return <WrappedComponent {...props} />; // spread all props through
  };
}

// ===== HOC 2: withLoading — show loader while data loads =====
function withLoading(WrappedComponent) {
  return function WithLoadingComponent({ isLoading, ...props }) {
    if (isLoading) {
      return (
        <div className="loading-spinner">
          <div className="spinner" />
          <p>Loading...</p>
        </div>
      );
    }
    return <WrappedComponent {...props} />;
  };
}

// ===== HOC 3: withDataFetch — manages API call for any component =====
function withDataFetch(url) {
  return function(WrappedComponent) {
    return function DataFetchedComponent(props) {
      const [data, setData] = useState(null);
      const [loading, setLoading] = useState(true);
      const [error, setError] = useState(null);

      useEffect(() => {
        fetch(url)
          .then(res => res.json())
          .then(data => { setData(data); setLoading(false); })
          .catch(err => { setError(err.message); setLoading(false); });
      }, []);

      // Inject data, loading, error as props to wrapped component
      return (
        <WrappedComponent
          {...props}
          data={data}
          loading={loading}
          error={error}
        />
      );
    };
  };
}

// ===== Usage =====
function UserList({ data, loading, error }) {
  if (loading) return <p>Loading...</p>;
  if (error) return <p>Error: {error}</p>;
  return (
    <ul>
      {data?.map(user => <li key={user.id}>{user.name}</li>)}
    </ul>
  );
}

// Compose HOCs — applied right to left
const ProtectedUserList = withAuth(
  withDataFetch('https://jsonplaceholder.typicode.com/users')(UserList)
);

// Use in app — all HOC props injected automatically
function App() {
  return <ProtectedUserList />;
}

