import React, { useState, useEffect, Fragment } from 'react';

// ===== useState — complete examples =====
function Counter() {
  const [count, setCount] = useState(0);
  const [step, setStep] = useState(1);

  // Object state — always spread to update
  const [user, setUser] = useState({ name: 'Alice', age: 25, city: 'Delhi' });

  // Array state — use spread for immutable updates
  const [todos, setTodos] = useState([]);
  const [newTodo, setNewTodo] = useState('');

  const addTodo = () => {
    if (!newTodo.trim()) return;
    setTodos(prev => [...prev, { id: Date.now(), text: newTodo, done: false }]);
    setNewTodo('');
  };

  const toggleTodo = (id) => {
    setTodos(prev =>
      prev.map(todo => todo.id === id ? { ...todo, done: !todo.done } : todo)
    );
  };

  const deleteTodo = (id) => {
    setTodos(prev => prev.filter(todo => todo.id !== id));
  };

  return (
    <Fragment>  {/* No extra DOM node */}
      <div>
        <p>Count: {count}</p>
        <button onClick={() => setCount(prev => prev + step)}>+{step}</button>
        <button onClick={() => setCount(0)}>Reset</button>
        <input type="number" value={step} onChange={e => setStep(+e.target.value)} min="1" />
      </div>

      <div>
        <input value={newTodo} onChange={e => setNewTodo(e.target.value)} placeholder="Add todo" />
        <button onClick={addTodo}>Add</button>
        <ul>
          {todos.map(todo => (
            <li key={todo.id}>
              <span style={{ textDecoration: todo.done ? 'line-through' : 'none' }}>
                {todo.text}
              </span>
              <button onClick={() => toggleTodo(todo.id)}>✓</button>
              <button onClick={() => deleteTodo(todo.id)}>✕</button>
            </li>
          ))}
        </ul>
      </div>
    </Fragment>
  );
}

// ===== useEffect — all patterns =====
function UserProfile({ userId }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  // Pattern 1: Run once on mount (empty dependency array)
  useEffect(() => {
    document.title = 'User Profile';
    return () => { document.title = 'App'; }; // cleanup on unmount
  }, []);

  // Pattern 2: Run when userId changes
  useEffect(() => {
    let cancelled = false;  // prevent state update on unmounted component
    setLoading(true);

    fetch(`https://jsonplaceholder.typicode.com/users/${userId}`)
      .then(res => res.json())
      .then(data => {
        if (!cancelled) {
          setUser(data);
          setLoading(false);
        }
      });

    return () => { cancelled = true; };  // cleanup: cancel stale request
  }, [userId]);  // re-runs whenever userId prop changes

  // Pattern 3: Timer with cleanup
  useEffect(() => {
    const timer = setInterval(() => console.log('tick'), 1000);
    return () => clearInterval(timer);  // cleanup: prevents memory leak
  }, []);

  if (loading) return <p>Loading...</p>;
  return <div><h2>{user?.name}</h2><p>{user?.email}</p></div>;
}

