// ===== useRef =====
function FocusInput() {
  const inputRef = useRef(null);   // ref for DOM access
  const renderCount = useRef(0);   // ref for counting renders (no re-render)
  const timerRef = useRef(null);   // ref for timer ID

  renderCount.current += 1;  // mutate ref directly — no re-render

  useEffect(() => {
    inputRef.current?.focus();  // focus input on mount
    timerRef.current = setInterval(() => console.log('tick'), 1000);
    return () => clearInterval(timerRef.current); // cleanup
  }, []);

  return (
    <div>
      <p>Renders: {renderCount.current}</p>
      <input ref={inputRef} type="text" placeholder="Auto-focused" />
      <button onClick={() => inputRef.current.focus()}>Focus Input</button>
    </div>
  );
}

// ===== useReducer — Shopping Cart =====
const cartReducer = (state, action) => {
  switch (action.type) {
    case 'ADD_ITEM':
      const exists = state.items.find(i => i.id === action.payload.id);
      if (exists) {
        return { ...state, items: state.items.map(i =>
          i.id === action.payload.id ? { ...i, qty: i.qty + 1 } : i
        )};
      }
      return { ...state, items: [...state.items, { ...action.payload, qty: 1 }] };
    case 'REMOVE_ITEM':
      return { ...state, items: state.items.filter(i => i.id !== action.payload) };
    case 'CLEAR_CART':
      return { ...state, items: [] };
    default:
      return state;
  }
};

function ShoppingCart() {
  const [cart, dispatch] = useReducer(cartReducer, { items: [] });

  const total = cart.items.reduce((sum, item) => sum + item.price * item.qty, 0);

  return (
    <div>
      {cart.items.map(item => (
        <div key={item.id}>
          {item.name} x{item.qty} = ₹{item.price * item.qty}
          <button onClick={() => dispatch({ type: 'REMOVE_ITEM', payload: item.id })}>Remove</button>
        </div>
      ))}
      <p>Total: ₹{total}</p>
      <button onClick={() => dispatch({ type: 'ADD_ITEM', payload: { id: 1, name: 'Laptop', price: 50000 } })}>
        Add Laptop
      </button>
      <button onClick={() => dispatch({ type: 'CLEAR_CART' })}>Clear Cart</button>
    </div>
  );
}

// ===== useMemo — expensive computation =====
function ProductList({ products, searchQuery, sortBy }) {
  // Only recomputes when products, searchQuery, or sortBy changes
  const filteredAndSorted = useMemo(() => {
    console.log('Computing filtered list...');
    return products
      .filter(p => p.name.toLowerCase().includes(searchQuery.toLowerCase()))
      .sort((a, b) => sortBy === 'price' ? a.price - b.price : a.name.localeCompare(b.name));
  }, [products, searchQuery, sortBy]);

  return <ul>{filteredAndSorted.map(p => <li key={p.id}>{p.name} - ₹{p.price}</li>)}</ul>;
}

// ===== useCallback — stable function reference =====
const MemoizedChild = React.memo(function Child({ onClick }) {
  console.log('Child rendered');  // only logs when props actually change
  return <button onClick={onClick}>Click</button>;
});

function Parent() {
  const [count, setCount] = useState(0);
  const [other, setOther] = useState(0);

  // Without useCallback: new function created on every render → Child re-renders
  // With useCallback: same function reference → Child does NOT re-render when 'other' changes
  const handleClick = useCallback(() => {
    setCount(prev => prev + 1);
  }, []);  // empty deps: function never changes

  return (
    <div>
      <p>Count: {count}, Other: {other}</p>
      <button onClick={() => setOther(p => p + 1)}>Change Other</button>
      <MemoizedChild onClick={handleClick} />
    </div>
  );
}

// ===== Custom Hook: useFetch =====
function useFetch(url) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    setError(null);

    fetch(url)
      .then(res => {
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        return res.json();
      })
      .then(data => { if (!cancelled) { setData(data); setLoading(false); } })
      .catch(err => { if (!cancelled) { setError(err.message); setLoading(false); } });

    return () => { cancelled = true; };
  }, [url]);

  return { data, loading, error };
}

// Custom Hook: useLocalStorage
function useLocalStorage(key, initialValue) {
  const [value, setValue] = useState(() => {
    try {
      const stored = localStorage.getItem(key);
      return stored ? JSON.parse(stored) : initialValue;
    } catch { return initialValue; }
  });

  const setStoredValue = (newValue) => {
    setValue(newValue);
    localStorage.setItem(key, JSON.stringify(newValue));
  };

  return [value, setStoredValue];
}

// Usage of custom hooks
