        Toggle Theme (persisted: {theme})
      </button>
      {users?.map(u => <p key={u.id}>{u.name}</p>)}
    </div>
  );
}

import React, { createContext, useContext, useState, useCallback } from 'react';

// ===== Step 1: Create contexts =====
const AuthContext = createContext(null);
const ThemeContext = createContext('light');

// ===== Step 2: Create Provider components =====
function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(false);

  const login = useCallback(async (email, password) => {
    setLoading(true);
    try {
      // Simulate API call
      const userData = { id: 1, name: 'Alice', email, role: 'admin' };
      setUser(userData);
      localStorage.setItem('user', JSON.stringify(userData));
    } finally {
      setLoading(false);
    }
  }, []);

  const logout = useCallback(() => {
    setUser(null);
    localStorage.removeItem('user');
  }, []);

  return (
    <AuthContext.Provider value={{ user, loading, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
}

function ThemeProvider({ children }) {
  const [theme, setTheme] = useState('light');
  const toggleTheme = () => setTheme(t => t === 'light' ? 'dark' : 'light');

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
}

// ===== Custom hooks for consuming context (best practice) =====
function useAuth() {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth must be used within AuthProvider');
  return context;
}

function useTheme() {
  return useContext(ThemeContext);
}

// ===== Step 3: Consume in any nested component =====
