import React, { useState } from 'react';

// ===== All conditional rendering patterns =====
function StatusDisplay({ status, user, items, error }) {

  // Pattern 1: Early return (cleanest for loading/error states)
  if (status === 'loading') return <div className="spinner">Loading...</div>;
  if (error) return <div className="error">Error: {error}</div>;
  if (!user) return null;  // render nothing

  // Pattern 2: Enum pattern — avoids nested ternaries
  const ROLE_BADGE = {
    admin:  <span className="badge badge-red">Admin</span>,
    editor: <span className="badge badge-blue">Editor</span>,
    viewer: <span className="badge badge-grey">Viewer</span>,
  };

  return (
    <div>
      {/* Pattern 3: Ternary */}
      <h1>{user.isPremium ? '⭐ Premium Member' : 'Free Member'}</h1>

      {/* Pattern 4: Logical && — be careful with 0! */}
      {user.unreadCount > 0 && <span>🔔 {user.unreadCount} unread</span>}

      {/* Enum lookup */}
      {ROLE_BADGE[user.role] ?? <span>Unknown role</span>}

      {/* Multiple conditions with IIFE */}
      {(() => {
        if (user.age < 18) return <p>Minor account</p>;
        if (user.age < 60) return <p>Adult account</p>;
        return <p>Senior account</p>;
      })()}
    </div>
  );
}

// ===== List rendering — complete example =====
function TodoList() {
  const [todos, setTodos] = useState([
    { id: 1, text: 'Learn React', done: true, priority: 'high' },
    { id: 2, text: 'Build project', done: false, priority: 'high' },
    { id: 3, text: 'Deploy app', done: false, priority: 'medium' },
  ]);
  const [filter, setFilter] = useState('all'); // 'all' | 'done' | 'pending'

  const filteredTodos = todos.filter(todo => {
    if (filter === 'done') return todo.done;
    if (filter === 'pending') return !todo.done;
    return true;
  });

  const PRIORITY_COLOR = { high: '#ff4444', medium: '#ff8c00', low: '#22cc22' };

  return (
    <div>
      <div>
        {['all', 'done', 'pending'].map(f => (
          <button
            key={f}
            onClick={() => setFilter(f)}
            style={{ fontWeight: filter === f ? 'bold' : 'normal' }}
          >
            {f}
          </button>
        ))}
      </div>

      {/* Empty state */}
      {filteredTodos.length === 0 ? (
        <p>No {filter} todos found.</p>
      ) : (
        <ul>
          {filteredTodos.map(todo => (
            <li
              key={todo.id}  // REQUIRED: stable unique id
              style={{ color: PRIORITY_COLOR[todo.priority] }}
            >
              <input
                type="checkbox"
                checked={todo.done}
                onChange={() => setTodos(prev =>
                  prev.map(t => t.id === todo.id ? { ...t, done: !t.done } : t)
                )}
              />
              <span style={{ textDecoration: todo.done ? 'line-through' : 'none' }}>
                {todo.text}
              </span>
            </li>
          ))}
        </ul>
      )}

      {/* Loading skeleton pattern */}
      {/* {isLoading && Array.from({ length: 3 }).map((_, i) => <SkeletonRow key={i} />)} */}
    </div>
  );
}

// ===== BEFORE: Class Component =====
class SearchBox extends React.Component {
  constructor(props) {
    super(props);
    this.state = { query: '', results: [], loading: false };
    this.handleSearch = this.handleSearch.bind(this);
    this.debounceTimer = null;
  }

  componentDidMount() {
    document.title = 'Search';
  }

  componentDidUpdate(prevProps, prevState) {
    if (prevState.query !== this.state.query) {
      clearTimeout(this.debounceTimer);
      this.debounceTimer = setTimeout(() => this.fetchResults(), 500);
    }
  }

  componentWillUnmount() {
    clearTimeout(this.debounceTimer);
    document.title = 'App';
  }

  async fetchResults() {
    this.setState({ loading: true });
    const res = await fetch(`/api/search?q=${this.state.query}`);
    const results = await res.json();
    this.setState({ results, loading: false });
  }

  handleSearch(e) { this.setState({ query: e.target.value }); }

  render() {
    const { query, results, loading } = this.state;
    return (
      <div>
        <input value={query} onChange={this.handleSearch} />
        {loading ? <p>Searching...</p> : results.map(r => <p key={r.id}>{r.title}</p>)}
      </div>
    );
  }
}

// ===== AFTER: Functional Component (equivalent) =====
import { useState, useEffect, useRef } from 'react';

function SearchBox() {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(false);
  const debounceTimer = useRef(null);  // ref replaces instance variable

  // componentDidMount equivalent
  useEffect(() => {
    document.title = 'Search';
    return () => { document.title = 'App'; };  // componentWillUnmount
  }, []);

  // componentDidUpdate equivalent — watch query changes
  useEffect(() => {
    if (!query) { setResults([]); return; }

    clearTimeout(debounceTimer.current);
    debounceTimer.current = setTimeout(async () => {
      setLoading(true);
      try {
        const res = await fetch(`/api/search?q=${query}`);
        const data = await res.json();
        setResults(data);
      } finally {
        setLoading(false);
      }
    }, 500);

    return () => clearTimeout(debounceTimer.current);  // cleanup
  }, [query]);

  return (
    <div>
      <input value={query} onChange={e => setQuery(e.target.value)} placeholder="Search..." />
      {loading ? <p>Searching...</p> : results.map(r => <p key={r.id}>{r.title}</p>)}
    </div>
  );
}

