// ===== 2. React Query (TanStack Query) =====
import { QueryClient, QueryClientProvider, useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { toast } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';

const queryClient = new QueryClient({
  defaultOptions: {
    queries: { staleTime: 5 * 60 * 1000, retry: 2 }, // cache 5 min, retry twice
  },
});

function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <ToastContainer position="top-right" autoClose={3000} />
      <UserManager />
    </QueryClientProvider>
  );
}

function UserManager() {
  const qc = useQueryClient();

  // Fetch users — handles loading, error, caching automatically
  const { data: users, isLoading, error, refetch } = useQuery({
    queryKey: ['users'],                 // cache key
    queryFn: userApi.getAll,             // fetch function
    staleTime: 5 * 60 * 1000,           // consider fresh for 5 mins
    select: (data) => data.sort((a, b) => a.name.localeCompare(b.name)), // transform
  });

  // Create user mutation
  const createMutation = useMutation({
    mutationFn: userApi.create,
    onSuccess: (newUser) => {
      // Optimistic update — add to cache immediately
      qc.setQueryData(['users'], old => [...old, newUser]);
      toast.success(`User ${newUser.name} created!`);
    },
    onError: (error) => {
      toast.error(`Failed: ${error.message}`);
    },
  });

  // Delete mutation
  const deleteMutation = useMutation({
    mutationFn: userApi.delete,
    onSuccess: (_, userId) => {
      qc.setQueryData(['users'], old => old.filter(u => u.id !== userId));
      toast.success('User deleted');
    },
  });

  if (isLoading) return <div className="spinner">Loading users...</div>;
  if (error) return <div>Error: {error.message} <button onClick={refetch}>Retry</button></div>;

  return (
    <div>
      <button
        onClick={() => createMutation.mutate({ name: 'New User', email: 'new@test.com' })}
        disabled={createMutation.isPending}
      >
        {createMutation.isPending ? 'Creating...' : 'Add User'}
      </button>
      {users?.map(user => (
        <div key={user.id}>
          <span>{user.name} — {user.email}</span>
          <button onClick={() => deleteMutation.mutate(user.id)} disabled={deleteMutation.isPending}>
            Delete
          </button>
        </div>
      ))}
    </div>
  );
}

