import { createSlice, createAsyncThunk, configureStore } from '@reduxjs/toolkit';
import { Provider, useSelector, useDispatch } from 'react-redux';

// ===== 1. Async thunk for API call =====
export const fetchUsers = createAsyncThunk(
  'users/fetchAll',  // action type prefix
  async (_, { rejectWithValue }) => {
    try {
      const res = await fetch('https://jsonplaceholder.typicode.com/users');
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      return await res.json();  // becomes action.payload in fulfilled
    } catch (error) {
      return rejectWithValue(error.message); // becomes action.payload in rejected
    }
  }
);

export const deleteUser = createAsyncThunk(
  'users/delete',
  async (userId, { rejectWithValue }) => {
    try {
      await fetch(`https://jsonplaceholder.typicode.com/users/${userId}`, { method: 'DELETE' });
      return userId;  // return id to remove from state
    } catch (error) {
      return rejectWithValue(error.message);
    }
  }
);

// ===== 2. Create Slice (replaces actions + reducer) =====
const usersSlice = createSlice({
  name: 'users',
  initialState: {
    list: [],
    loading: false,  // 'idle' | 'pending' | 'succeeded' | 'failed'
    error: null,
    selectedId: null,
  },
  reducers: {
    // Synchronous actions
    selectUser: (state, action) => {
      state.selectedId = action.payload;  // RTK uses Immer — 'mutation' is safe
    },
    clearSelection: (state) => {
      state.selectedId = null;
    },
  },
  extraReducers: (builder) => {
    builder
      // fetchUsers lifecycle
      .addCase(fetchUsers.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(fetchUsers.fulfilled, (state, action) => {
        state.loading = false;
        state.list = action.payload;
      })
      .addCase(fetchUsers.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload;
      })
      // deleteUser lifecycle
      .addCase(deleteUser.fulfilled, (state, action) => {
        state.list = state.list.filter(u => u.id !== action.payload);
      });
  },
});

export const { selectUser, clearSelection } = usersSlice.actions;

// ===== 3. Configure Store =====
const store = configureStore({
  reducer: {
    users: usersSlice.reducer,
    // add more slices here: cart: cartSlice.reducer
  },
  // Redux DevTools and Thunk middleware added automatically by RTK
});

// ===== 4. Selectors =====
const selectAllUsers = state => state.users.list;
const selectLoading = state => state.users.loading;
const selectError = state => state.users.error;

// ===== 5. Components using Redux =====
function UserList() {
  const dispatch = useDispatch();
  const users = useSelector(selectAllUsers);
  const loading = useSelector(selectLoading);
  const error = useSelector(selectError);

  // Fetch on mount
  React.useEffect(() => {
    dispatch(fetchUsers());
  }, [dispatch]);

  if (loading) return <p>Loading users...</p>;
  if (error) return (
    <div>
      <p>Error: {error}</p>
      <button onClick={() => dispatch(fetchUsers())}>Retry</button>
    </div>
  );

  return (
    <ul>
      {users.map(user => (
        <li key={user.id}>
          {user.name} — {user.email}
          <button onClick={() => dispatch(selectUser(user.id))}>Select</button>
          <button onClick={() => dispatch(deleteUser(user.id))}>Delete</button>
        </li>
      ))}
    </ul>
  );
}

// ===== 6. Root with Provider =====
function App() {
  return (
    <Provider store={store}>
      <UserList />
    </Provider>
  );
}

