// ===== React Portal — Modal =====
function Modal({ isOpen, onClose, title, children }) {
  if (!isOpen) return null;

  // Renders into document.body — escapes any overflow:hidden parents
  return ReactDOM.createPortal(
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-box" onClick={e => e.stopPropagation()}>
        <button className="modal-close" onClick={onClose}>✕</button>
        <h2>{title}</h2>
        {children}
      </div>
    </div>,
    document.body  // render target
  );
}

// ===== Infinite Scroll with IntersectionObserver =====
function InfiniteList() {
  const [items, setItems] = useState(Array.from({ length: 20 }, (_, i) => i + 1));
  const [loading, setLoading] = useState(false);
  const [page, setPage] = useState(1);
  const sentinelRef = useRef(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        if (entries[0].isIntersecting && !loading) {
          loadMore();
        }
      },
      { threshold: 0.1 }
    );
    if (sentinelRef.current) observer.observe(sentinelRef.current);
    return () => observer.disconnect();
  }, [loading]);

  const loadMore = async () => {
    setLoading(true);
    await new Promise(r => setTimeout(r, 800)); // simulate API
    const newItems = Array.from({ length: 20 }, (_, i) => (page * 20) + i + 1);
    setItems(prev => [...prev, ...newItems]);
    setPage(p => p + 1);
    setLoading(false);
  };

  return (
    <div style={{ height: '500px', overflow: 'auto' }}>
      {items.map(item => <div key={item} style={{ padding: '20px', borderBottom: '1px solid #eee' }}>Item {item}</div>)}
      <div ref={sentinelRef} style={{ height: '1px' }} />  {/* sentinel */}
      {loading && <p>Loading more...</p>}
    </div>
  );
}

// ===== Error Boundary =====
class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error) {
    return { hasError: true, error }; // show fallback UI
  }

  componentDidCatch(error, info) {
    // Log to error tracking
    console.error('Error caught:', error, info.componentStack);
    // errorTrackingService.log(error, info);
  }

  render() {
    if (this.state.hasError) {
      return (
        this.props.fallback || (
          <div className="error-boundary">
            <h2>Something went wrong</h2>
            <p>{this.state.error?.message}</p>
            <button onClick={() => this.setState({ hasError: false, error: null })}>
              Try Again
            </button>
          </div>
        )
      );
    }
    return this.props.children;
  }
}

// Usage
function App() {
  return (
    <ErrorBoundary fallback={<h1>App crashed. Please refresh.</h1>}>
      <ErrorBoundary>  {/* per-section boundaries */}
        <UserSection />
      </ErrorBoundary>
      <ErrorBoundary>
        <ProductSection />
      </ErrorBoundary>
    </ErrorBoundary>
  );
}

